package main

import (
	"crypto/rand"
	"math/big"
)

func generateRandomSessionToken() string {
	token := ""
	for i := 0; i < 32; i++ {
		randomByte, err := rand.Int(rand.Reader, big.NewInt(1<<8))
		if err != nil {
			panic(err)
		}
		token += string(randomByte.Bytes()[0])
	}
	return token
}